// Main SOAP Web Service
@WebService(
    name = "OrderProcessingService",
    serviceName = "B2BOrderService",
    targetNamespace = "http://b2b.ecommerce.com/orders"
)
@SOAPBinding(style = SOAPBinding.Style.DOCUMENT, use = SOAPBinding.Use.LITERAL)
public class OrderProcessingService {

    private static final double TAX_RATE = 0.08;
    private static final double FREE_SHIPPING_THRESHOLD = 500.0;
    private static final double STANDARD_SHIPPING_COST = 25.0;
    private static final double B2B_DISCOUNT_THRESHOLD = 1000.0;
    private static final double B2B_DISCOUNT_RATE = 0.05;

    private static final ConcurrentHashMap<String, OrderResponse> orderStore = new ConcurrentHashMap<>();
    private static final SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss");

    @WebMethod(operationName = "processOrder")
    public OrderResponse processOrder(
            @WebParam(name = "orderRequest") OrderRequest orderRequest) {

        OrderResponse response = new OrderResponse();

        try {
            // Validate the order request
            String validationError = validateOrderRequest(orderRequest);
            if (validationError != null) {
                response.setStatus("REJECTED");
                response.setMessage("Order validation failed: " + validationError);
                return response;
            }

            // Generate order ID
            String orderId = "B2B-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();
            response.setOrderId(orderId);

            // Process each item and calculate line totals
            List<OrderItem> processedItems = new ArrayList<>();
            double subtotal = 0.0;

            for (OrderItem item : orderRequest.getItems()) {
                double lineTotal = item.getUnitPrice() * item.getQuantity();
                item.setLineTotal(lineTotal);
                subtotal += lineTotal;
                processedItems.add(item);

                System.out.println("Processing item: " + item.getItemName() +
                        " | Qty: " + item.getQuantity() +
                        " | Unit Price: $" + item.getUnitPrice() +
                        " | Line Total: $" + lineTotal);
            }

            response.setProcessedItems(processedItems);
            response.setSubtotal(roundToTwoDecimals(subtotal));

            // Apply B2B bulk discount
            double discountedSubtotal = subtotal;
            if (subtotal >= B2B_DISCOUNT_THRESHOLD) {
                discountedSubtotal = subtotal * (1 - B2B_DISCOUNT_RATE);
                System.out.println("B2B discount applied: " + (B2B_DISCOUNT_RATE * 100) + "% off");
            }

            // Calculate tax
            double tax = discountedSubtotal * TAX_RATE;
            response.setTax(roundToTwoDecimals(tax));

            // Calculate shipping
            double shippingCost = (discountedSubtotal >= FREE_SHIPPING_THRESHOLD) ? 0.0 : STANDARD_SHIPPING_COST;
            response.setShippingCost(roundToTwoDecimals(shippingCost));

            // Calculate total price
            double totalPrice = discountedSubtotal + tax + shippingCost;
            response.setTotalPrice(roundToTwoDecimals(totalPrice));

            // Set order dates
            Date now = new Date();
            response.setOrderDate(dateFormat.format(now));

            Date estimatedDelivery = new Date(now.getTime() + (5L * 24 * 60 * 60 * 1000));
            response.setEstimatedDelivery(dateFormat.format(estimatedDelivery));

            // Set status
            response.setStatus("CONFIRMED");
            response.setMessage("Order processed successfully. " +
                    processedItems.size() + " item(s) confirmed. " +
                    (subtotal >= B2B_DISCOUNT_THRESHOLD ?
                            "B2B discount of " + (B2B_DISCOUNT_RATE * 100) + "% applied. " : "") +
                    (shippingCost == 0.0 ? "Free shipping applied." : "Standard shipping charged."));

            // Store order for status tracking
            orderStore.put(orderId, response);

            System.out.println("Order " + orderId + " processed successfully. Total: $" + totalPrice);

        } catch (Exception e) {
            response.setStatus("ERROR");
            response.setMessage("Error processing order: " + e.getMessage());
            System.err.println("Error processing order: " + e.getMessage());
            e.printStackTrace();
        }

        return response;
    }

    @WebMethod(operationName = "processSingleItemOrder")
    public OrderResponse processSingleItemOrder(
            @WebParam(name = "customerId") String customerId,
            @WebParam(name = "customerName") String customerName,
            @WebParam(name = "itemId") String itemId,
            @WebParam(name = "itemName") String itemName,
            @WebParam(name = "unitPrice") double unitPrice,
            @WebParam(name = "quantity") int quantity,
            @WebParam(name = "shippingAddress") String shippingAddress) {

        OrderRequest request = new OrderRequest();
        request.setCustomerId(customerId);
        request.setCustomerName(customerName);
        request.setShippingAddress(shippingAddress);
        request.setPaymentMethod("INVOICE");

        OrderItem item = new OrderItem(itemId, itemName, unitPrice, quantity);
        List<OrderItem> items = new ArrayList<>();
        items.add(item);
        request.setItems(items);

        return processOrder(request);
    }

    @WebMethod(operationName = "calculateOrderTotal")
    public double calculateOrderTotal(
            @WebParam(name = "itemPrices") double[] itemPrices,
            @WebParam(name = "itemQuantities") int[] itemQuantities) {

        if (itemPrices == null || itemQuantities == null ||
                itemPrices.length != itemQuantities.length) {
            return -1.0;
        }

        double subtotal = 0.0;
        for (int i = 0; i < itemPrices.length; i++) {
            if (itemPrices[i] < 0 || itemQuantities[i] < 0) {
                return -1.0;
            }
            subtotal += itemPrices[i] * itemQuantities[i];
        }

        // Apply B2B discount
        if (subtotal >= B2B_DISCOUNT_THRESHOLD) {
            subtotal *= (1 - B2B_DISCOUNT_RATE);
        }

        double tax = subtotal * TAX_RATE;
        double shipping = (subtotal >= FREE_SHIPPING_THRESHOLD) ? 0.0 : STANDARD_SHIPPING_COST;

        return roundToTwoDecimals(subtotal + tax + shipping);
    }

    @WebMethod(operationName = "getOrderStatus")
    public OrderStatusResponse getOrderStatus(
            @WebParam(name = "orderId") String orderId) {

        OrderStatusResponse statusResponse = new OrderStatusResponse();
        statusResponse.setOrderId(orderId);

        if (orderId == null || orderId.trim().isEmpty()) {
            statusResponse.setStatus("ERROR");
            statusResponse.setLastUpdated(dateFormat.format(new Date()));
            return statusResponse;
        }

        OrderResponse storedOrder = orderStore.get(orderId);
        if (storedOrder != null) {
            statusResponse.setStatus(storedOrder.getStatus());
            statusResponse.setTotalPrice(storedOrder.getTotalPrice());
            statusResponse.setLastUpdated(dateFormat.format(new Date()));
        } else {
            statusResponse.setStatus("NOT_FOUND");
            statusResponse.setLastUpdated(dateFormat.format(new Date()));
        }

        return statusResponse;
    }

    @WebMethod(operationName = "cancelOrder")
    public OrderResponse cancelOrder(
            @WebParam(name = "orderId") String orderId,
            @WebParam(name = "reason") String reason) {

        OrderResponse response = new OrderResponse();
        response.setOrderId(orderId);

        if (orderId == null || orderId.trim().isEmpty()) {
            response.setStatus("ERROR");
            response.setMessage("Order ID is required for cancellation.");
            return response;
        }

        OrderResponse storedOrder = orderStore.get(orderId);
        if (storedOrder != null) {
            if ("CANCELLED".equals(storedOrder.getStatus())) {
                response.setStatus("ERROR");
                response.setMessage("Order " + orderId + " is already cancelled.");
            } else {
                storedOrder.setStatus("CANCELLED");
                storedOrder.setMessage("Order cancelled. Reason: " + (reason != null ? reason : "Not specified"));
                orderStore.put(orderId, storedOrder);

                response.setStatus("CANCELLED");
                response.setMessage("Order " + orderId + " has been successfully cancelled.");
                response.setTotalPrice(storedOrder.getTotalPrice());
                System.out.println("Order " + orderId + " cancelled. Reason: " + reason);
            }
        } else {
            response.setStatus("NOT_FOUND");
            response.setMessage("Order " + orderId + " not found in the system.");
        }

        return response;
    }

    @WebMethod(operationName = "getBulkPriceQuote")
    public double getBulkPriceQuote(
            @WebParam(name = "unitPrice") double unitPrice,
            @WebParam(name = "quantity") int quantity) {

        if (unitPrice <= 0 || quantity <= 0) {
            return -1.0;
        }

        double baseTotal = unitPrice * quantity;

        // Tiered B2B pricing
        double discountRate = 0.0;
        if (quantity >= 1000) {
            discountRate = 0.15;
        } else if (quantity >= 500) {
            discountRate = 0.10;
        } else if (quantity >= 100) {
            discountRate = 0.07;
        } else if (quantity >= 50) {
            discountRate = 0.05;
        } else if (quantity >= 10) {
            discountRate = 0.02;
        }

        double discountedTotal = baseTotal * (1 - discountRate);
        double tax = discountedTotal * TAX_RATE;
        double shipping = (discountedTotal >= FREE_SHIPPING_THRESHOLD) ? 0.0 : STANDARD_SHIPPING_COST;

        return roundToTwoDecimals(discountedTotal + tax + shipping);
    }

    // Validation method
    private String validateOrderRequest(OrderRequest request) {
        if (request == null) {
            return "Order request is null.";
        }
        if (request.getCustomerId() == null || request.getCustomerId().trim().isEmpty()) {
            return "Customer ID is required.";
        }
        if (request.getCustomerName() == null || request.getCustomerName().trim().isEmpty()) {
            return "Customer name is required.";
        }
        if (request.getShippingAddress() == null || request.getShippingAddress().trim().isEmpty()) {
            return "Shipping address is required.";
        }
        if (request.getItems() == null || request.getItems().isEmpty()) {
            return "At least one order item is required.";
        }

        for (OrderItem item : request.getItems()) {
            if (item.getItemId() == null || item.getItemId().trim().isEmpty()) {
                return "Item ID is required for all items.";
            }
            if (item.getUnitPrice() <= 0) {
                return "Item price must be greater than zero for item: " + item.getItemId();
            }
            if (item.getQuantity() <= 0) {
                return "Item quantity must be greater than zero for item: " + item.getItemId();
            }
        }

        return null;
    }

    private double roundToTwoDecimals(double value) {
        return Math.round(value * 100.0) / 100.0;
    }

    // Main method to publish the service
    public static void main(String[] args) {
        String url = "http://localhost:8080/b2b/orders";
        System.out.println("Starting B2B Order Processing SOAP Web Service...");
        System.out.println("Publishing service at: " + url);
        System.out.println("WSDL available at: " + url + "?wsdl");

        Endpoint endpoint = Endpoint.publish(url, new OrderProcessingService());

        System.out.println("B2B Order Processing Service is running.");
        System.out.println("Tax Rate: " + (TAX_RATE * 100) + "%");
        System.out.println("Free Shipping Threshold: $" + FREE_SHIPPING_THRESHOLD);
        System.out.println("B2B Discount Threshold: $" + B2B_DISCOUNT_THRESHOLD);
        System.out.println("B2B Discount Rate: " + (B2B_DISCOUNT_RATE * 100) + "%");
        System.out.println("Press Ctrl+C to stop the service.");

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("\nShutting down B2B Order Processing Service...");
            endpoint.stop();
            System.out.println("Service stopped.");
        }));
    }
}